1621	    state: &mut LuaState,
1622	    nargs: i32,
1623	    nresults: i32,
1624	    errfunc: i32,
1625	    ctx: isize,
1626	    k: Option<fn(&mut LuaState, i32, isize) -> Result<usize, LuaError>>,
1627	) -> Result<LuaStatus, LuaError> {
1628	    // C: api_checknelems(L, nargs+1);
1629	    // C: func (error handler) stack offset
1630	    let err_handler_idx: isize = if errfunc == 0 {
1631	        0
1632	    } else {
1633	        let o = index_to_stack_idx(state, errfunc);
1634	        debug_assert!(
1635	            matches!(state.get_at(o), LuaValue::Function(_)),
1636	            "error handler must be a function"
1637	        );
1638	        o.0 as isize
1639	    };
1640	    let top = state.top_idx();
1641	    let func_idx = top - (nargs + 1);
1642	    // C: if (k == NULL || !yieldable(L)) { conventional protected call }
1643	    // TODO(port): continuation and yieldable deferred to Phase E.
1644	    let _ = (k, ctx);
1645	    state.protected_call_raw(func_idx, nresults, StackIdx(err_handler_idx as u32))?;
1646	    state.adjust_results(nresults);
1647	    Ok(LuaStatus::Ok)
1648	}
