1650	// C: LUA_API int lua_load (lua_State *L, lua_Reader reader, void *data,
1651	//                          const char *chunkname, const char *mode)
1652	// PORT NOTE: lua_Reader (void* callback) is replaced by Box<dyn FnMut>; mode
1653	// is &[u8].
1654	pub fn load(
1655	    state: &mut LuaState,
1656	    reader: Box<dyn FnMut() -> Option<Vec<u8>>>,
1657	    chunkname: Option<&[u8]>,
1658	    mode: Option<&[u8]>,
1659	) -> Result<LuaStatus, LuaError> {
1660	    let name = chunkname.unwrap_or(b"?");
1661	    // C: luaZ_init(L, &z, reader, data); status = luaD_protectedparser(L, &z, chunkname, mode);
1662	    let z = crate::zio::ZIO::new(reader);
1663	    let status = state.protected_parser(z, name, mode);
1664	    if status == LuaStatus::Ok {
1665	        // C: LClosure *f = clLvalue(s2v(L->top.p - 1));
